// MARK: - Data Hex Extensions

extension Data {
    var hexString: String {
        return map { String(format: "%02hhx", $0) }.joined()
    }
    
    init?(hexString: String) {
        let len = hexString.count
        guard len % 2 == 0 else { return nil }
        
        var data = Data(capacity: len / 2)
        var index = hexString.startIndex
        
        for _ in 0..<len / 2 {
            let nextIndex = hexString.index(index, offsetBy: 2)
            guard let byte = UInt8(hexString[index..<nextIndex], radix: 16) else {
                return nil
            }
            data.append(byte)
            index = nextIndex
        }
        
        self = data
    }
}

// MARK: - Offline Authentication Manager

final class OfflineAuthenticationManager {
    
    enum AuthResult {
        case success
        case failure
        case noStoredPassword
        case error(String)
    }
    
    private let userIdentifierPrefix = "user_"
    
    // Register a new user password for offline auth
    func registerPassword(_ password: String, forUser userId: String) -> AuthResult {
        let identifier = userIdentifierPrefix + userId
        
        do {
            try SecurePasswordStorage.storePassword(password, forIdentifier: identifier)
            return .success
        } catch let error as SecurePasswordStorage.StorageError {
            return .error(error.description)
        } catch {
            return .error("Unexpected error: \(error.localizedDescription)")
        }
    }
    
    // Authenticate user offline
    func authenticate(password: String, forUser userId: String) -> AuthResult {
        let identifier = userIdentifierPrefix + userId
        
        guard SecurePasswordStorage.hasStoredPassword(forIdentifier: identifier) else {
            return .noStoredPassword
        }
        
        do {
            let isValid = try SecurePasswordStorage.verifyPassword(password, forIdentifier: identifier)
            return isValid ? .success : .failure
        } catch let error as SecurePasswordStorage.StorageError {
            return .error(error.description)
        } catch {
            return .error("Unexpected error: \(error.localizedDescription)")
        }
    }
    
    // Update password
    func updatePassword(currentPassword: String, newPassword: String, forUser userId: String) -> AuthResult {
        // First verify the current password
        let authResult = authenticate(password: currentPassword, forUser: userId)
        
        switch authResult {
        case .success:
            // Current password verified, store new password
            return registerPassword(newPassword, forUser: userId)
        default:
            return authResult
        }
    }
    
    // Remove user credentials
    func removeCredentials(forUser userId: String) -> AuthResult {
        let identifier = userIdentifierPrefix + userId
        
        do {
            try SecurePasswordStorage.deletePassword(forIdentifier: identifier)
            return .success
        } catch let error as SecurePasswordStorage.StorageError {
            return .error(error.description)
        } catch {
            return .error("Unexpected error: \(error.localizedDescription)")
        }
    }
    
    // Check if user has stored credentials
    func hasCredentials(forUser userId: String) -> Bool {
        let identifier = userIdentifierPrefix + userId
        return SecurePasswordStorage.hasStoredPassword(forIdentifier: identifier)
    }
}

